content.text:
 1	.kv-getting-started-grid {
 2	  --min-column-width: 220px;
 3	
 4	  // Increase css specificity to override a generic [class*="pf-v5-c-"] rule.
 5	  &__header.pf-v6-c-card__header {
 6	    // Use padding sm instead of lg to fix alignment of the KebabToggle action button.
 7	    padding-right: var(--pf-t--global--spacer--200);
 8	    padding-block-start: 0;
 9	  }
10	
11	  &__tooltip-icon {
12	    margin-left: var(--pf-t--global--spacer--200);
13	  }
14	
15	  &__action-dropdown {
16	    .pf-v5-c-dropdown__menu {
17	      width: 280px;
18	    }
19	    .pf-v5-c-dropdown__menu-item-description {
20	      white-space: pre-wrap;
21	    }
22	  }
23	
24	  // Increase css specificity to override a generic [class*="pf-v5-c-"] rule.
25	  &__content.pf-v6-c-card__body {
26	    display: grid;
27	    grid-template-columns: repeat(auto-fit, minmax(var(--min-column-width), 1fr));
28	
29	    // Keep only additional spacing at the bottom. Horizontal spacing is added to the child elements.
30	    padding: 0 0 calc(var(--pf-v6-c-card--child--PaddingBottom) / 2) 0;
31	    // Hide the border on the right side of the content. Works together wie negative margin below.
32	    overflow: hidden;
33	
34	    // Increase css specificity to override a generic [class*="pf-v5-c-"] rule.
35	    > .pf-v6-l-flex.pf-m-grow.pf-m-column {
36	      // Show a divider on the right side and hide them in the latest column.
37	      border-right: var(--pf-t--global--border--width--regular) solid var(--pf-t--global--BorderColor--100);
38	      margin-right: calc(-1 * var(--pf-t--global--border--width--regular));
39	      // Padding around the card. Vertical spacing is splitted on the card and the grid.
40	      padding-top: calc(var(--pf-v6-c-card--first-child--PaddingTop) / 2);
41	      padding-bottom: calc(var(--pf-v6-c-card--child--PaddingBottom) / 2);
42	      padding-left: var(--pf-v6-c-card--child--PaddingLeft);
43	      padding-right: var(--pf-v6-c-card--child--PaddingRight);
44	    }
45	  }
46	
47	  &__tooltip {
48	    background: var(--pf-v6-c-page__main-section--m-light--BackgroundColor);
49	  }
50	
51	  &__expandable {
52	    background: var(--pf-v6-c-page__main-section--m-light--BackgroundColor);
53	
54	    .pf-v6-c-expandable-section__toggle-text {
55	      color: var(--pf-t--global--text--color--regular);
56	    }
57	  }
58	}

